from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of Triple objects about universities (or related entities)
    into a single fluent, coherent sentence.
    """
    if not triples:
        return ""

    # Clean object values - remove surrounding quotes if present
    def clean_value(val):
        val = val.strip()
        if val.startswith('"') and val.endswith('"'):
            return val[1:-1]
        return val

    # Group triples by subject to build structured information
    subject_info = {}
    for t in triples:
        if t.subject not in subject_info:
            subject_info[t.subject] = []
        subject_info[t.subject].append(t)

    # Identify the main subject - prioritize university entities
    main_subject = None
    for subj in subject_info.keys():
        subj_lower = subj.lower()
        if any(term in subj_lower for term in ["university", "college", "institute", "school", "academy"]):
            main_subject = subj
            break

    # Fallback to most common subject or first one
    if main_subject is None:
        main_subject = max(subject_info.keys(), key=lambda s: len(subject_info[s]))

    main_triples = subject_info[main_subject]

    # Collect all information including related subjects
    all_info_parts = []
    city_info = None
    country_info = None
    state_info = None
    other_info = []
    related_subjects = []

    # Process main subject triples
    for t in main_triples:
        obj = clean_value(t.object)
        if t.predicate == "city":
            city_info = obj
        elif t.predicate == "country":
            country_info = obj
        elif t.predicate == "state":
            state_info = obj
        elif t.predicate == "latinName":
            other_info.append(f"whose Latin name is {obj}")
        elif t.predicate == "nickname":
            other_info.append(f"also known as {obj}")
        elif t.predicate == "rector":
            other_info.append(f"with {obj} as rector")
        elif t.predicate == "dean":
            other_info.append(f"with {obj} as dean")
        elif t.predicate == "director":
            other_info.append(f"directed by {obj}")
        elif t.predicate == "president":
            other_info.append(f"with {obj} as president")
        elif t.predicate == "established":
            other_info.append(f"established in {obj}")
        elif t.predicate == "numberOfStudents":
            other_info.append(f"with {obj} students")
        elif t.predicate == "numberOfUndergraduateStudents":
            other_info.append(f"with {obj} undergraduate students")
        elif t.predicate == "numberOfPostgraduateStudents":
            other_info.append(f"with {obj} postgraduate students")
        elif t.predicate == "numberOfDoctoralStudents":
            other_info.append(f"with {obj} doctoral students")
        elif t.predicate == "academicStaffSize":
            other_info.append(f"with {obj} academic staff")
        elif t.predicate == "staff":
            other_info.append(f"with {obj} staff members")
        elif t.predicate == "affiliation":
            other_info.append(f"affiliated with {obj}")
        elif t.predicate == "location":
            other_info.append(f"located in {obj}")
        elif t.predicate == "campus":
            other_info.append(f"campus at {obj}")
        elif t.predicate == "motto":
            other_info.append(f"with the motto \"{obj}\"")
        elif t.predicate == "officialSchoolColour":
            other_info.append(f"with official colours {obj}")
        elif t.predicate == "sportsOffered":
            other_info.append(f"offering {obj}")
        elif t.predicate == "outlookRanking":
            other_info.append(f"ranked {obj} in the Outlook ranking")
        elif t.predicate == "founder":
            other_info.append(f"founded by {obj}")
        elif t.predicate == "wasGivenTheTechnicalCampusStatusBy":
            other_info.append(f"granted technical campus status by {obj}")
        elif t.predicate == "isPartOf":
            other_info.append(f"part of {obj}")
        else:
            other_info.append(f"with {t.predicate.replace('_', ' ')} {obj}")

    # Process related subjects (for context like city/country relationships)
    for subj, subj_triples in subject_info.items():
        if subj != main_subject:
            for t in subj_triples:
                obj = clean_value(t.object)
                if t.predicate == "capital" and country_info:
                    other_info.append(f"where the capital is {obj}")
                elif t.predicate == "founder":
                    other_info.append(f"the city was founded by {obj}")

    # Build the sentence
    sentence_parts = [main_subject]

    # Add location information in a natural hierarchical way
    location_parts = []
    if state_info:
        location_parts.append(state_info)
    if city_info:
        location_parts.append(city_info)
    if country_info:
        location_parts.append(country_info)

    if location_parts:
        sentence_parts.append(f"which is located in {', '.join(location_parts)}")

    # Add other information with appropriate connectors
    if other_info:
        if len(other_info) == 1:
            sentence_parts.append(f", {other_info[0]}")
        else:
            # Use "and" to connect the last item properly
            sentence_parts.append(f", {', '.join(other_info[:-1])}, and {other_info[-1]}")

    sentence = " ".join(sentence_parts) + "."

    # Clean up any double commas or awkward spacing
    sentence = sentence.replace(", ,", ",").replace("  ", " ")

    return sentence

# EVOLVE-BLOCK-END
